mapper.select:
select s.*,
       c.course_name,
       u.real_name as member_name
from review_record s
         left join repertoire_info c on s.course_id = c.id
         left join sys_user u on s.member_id = u.id


        and s.schedule_id = #{scheduleId}


        and s.member_id = #{memberId}


        and s.artist_id = #{artistId}


order by s.id desc

mapper.update:
update review_record
usual_score = #{usualScore}, exam_score = #{examScore}, total_score = #{totalScore}, grade_level = #{gradeLevel}, remark = #{remark},
where selection_id = #{selectionId}
